// /frontend/src/components/WeatherApp.jsx (or weather.js if that's your filename)
import React, { useEffect, useState } from "react";
import WeatherOverlay from "./WeatherOverlay";
import Radar from "./Radar";
import Forecast from "./Forecast";
import BottomBar from "./BottomBar";
import SearchSection from "./SearchSection";

// Fallback if nothing is stored yet
const ATL = { name: "Atlanta,US", lat: 33.7490, lon: -84.3880 };

// Helpers
const isFiniteNum = (n) => typeof n === "number" && isFinite(n);

export default function WeatherApp() {
  const [place, setPlace] = useState(ATL);

  const [weather, setWeather] = useState({
    current: null,
    hourly: [],
    daily: [],
    summary: "",
  });
  const [wLoading, setWLoading] = useState(false);
  const [wError, setWError] = useState("");

  // Fired by SearchSection when user picks a city
  function handleSearchSelect(p) {
    // Accept {name, lat, lon} or a plain string
    if (typeof p === "string") {
      setPlace({ name: p, lat: ATL.lat, lon: ATL.lon });
      return;
    }
    setPlace({
      name: p?.name || ATL.name,
      lat: isFiniteNum(p?.lat) ? p.lat : ATL.lat,
      lon: isFiniteNum(p?.lon) ? p.lon : ATL.lon,
    });
  }

  // Fetch backend whenever the selected place changes
  useEffect(() => {
    let abort = false;

    async function run() {
      try {
        setWLoading(true);
        setWError("");

        // With CRA proxy in package.json, ALWAYS use a RELATIVE path
        const res = await fetch("/api/weather/current", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            // Backend only uses `location`; extra fields are harmless.
            location: place.name,      // e.g., "Atlanta,US"
            lat: place.lat,
            lon: place.lon,
          }),
        });

        if (!res.ok) {
          const text = await res.text().catch(() => "");
          throw new Error(`HTTP ${res.status} ${text || res.statusText}`);
        }

        const data = await res.json();

        const normalized = {
          // Backend returns { weather: {...}, summary: "..." }
          current: data?.weather?.current ?? null,
          hourly: data?.weather?.hourly ?? [],
          daily: data?.weather?.daily ?? [],
          summary: data?.summary ?? "",
        };

        if (!abort) setWeather(normalized);
      } catch (e) {
        if (!abort) setWError(e.message || "Failed to load weather");
      } finally {
        if (!abort) setWLoading(false);
      }
    }

    if (place?.name) run();
    return () => { abort = true; };
  }, [place.name, place.lat, place.lon]);

  const now = weather.current || {};

  return (
    <div className="relative min-h-screen flex flex-col bg-white overflow-hidden">
      {/* Dynamic background overlays */}
      <WeatherOverlay condition={now?.weather} />

      {/* Top search */}
      <header className="px-4 pt-4">
        <SearchSection
          defaultValue={place?.name || ""}
          onSelect={handleSearchSelect}
        />
      </header>

      {/* Tiny status line */}
      {wLoading && (
        <div className="px-4 mt-2 text-xs text-gray-600">Loading weather…</div>
      )}
      {!wLoading && wError && (
        <div className="px-4 mt-2 text-xs text-red-600">{wError}</div>
      )}

      {/* Current city label */}
      <section className="px-4 mt-3 mb-2">
        <div className="text-sm text-gray-700">
          <span className="font-medium text-gray-900">{place?.name}</span>
        </div>
      </section>

      {/* Radar centered on the selected city */}
      <section className="px-4 mb-24">
        <Radar
          center={[place?.lat ?? ATL.lat, place?.lon ?? ATL.lon]}
          zoom={6}
          height={320}
          className="rounded-2xl overflow-hidden"
        />
      </section>

      {/* Forecast — now actually receives data */}
      <Forecast
        current={weather.current}
        hourly={weather.hourly}
        daily={weather.daily}
        summary={weather.summary}
      />

      {/* Bottom bar */}
      <BottomBar />
    </div>
  );
}
